function solve(nums) {
    const indices1 = [];
    const indices2 = [];

    // Collect indices where nums[i] is 1 or 2.
    // Since we iterate sequentially, these lists are naturally sorted.
    for (let i = 0; i < nums.length; i++) {
        if (nums[i] === 1) {
            indices1.push(i);
        } else if (nums[i] === 2) {
            indices2.push(i);
        }
    }

    // If either group is missing, no effective pair exists.
    if (indices1.length === 0 || indices2.length === 0) {
        return -1;
    }

    // Use two pointers approach to find the minimum absolute difference in O(N) time.
    let minDiff = Infinity;
    let p1 = 0; // Pointer for indices1
    let p2 = 0; // Pointer for indices2

    while (p1 < indices1.length && p2 < indices2.length) {
        const i = indices1[p1];
        const j = indices2[p2];

        const diff = Math.abs(i - j);

        if (diff < minDiff) {
            minDiff = diff;
        }

        // Advance the pointer corresponding to the smaller index.
        // This moves the smaller index towards the larger index, potentially reducing the difference.
        if (i < j) {
            p1++;
        } else {
            p2++;
        }
    }

    return minDiff;
}

